mapper.select:

from payment_offline_bank_statement_item i
where i.tenant_id = #{tenantId}
  and i.batch_id = #{batchId}
  and i.del_flag = 0
order by i.row_no asc, i.id asc

select count(1)
from payment_offline_bank_statement_item
where tenant_id = #{tenantId}
  and bank_account_no_mask <=> #{bankAccountNoMask}
  and bank_statement_no = #{bankStatementNo}
  and trade_date = #{tradeDate}
  and del_flag = 0
